    assert_eq!(diags.len(), 1);
    assert_eq!(diags[0].code, 2322);
    // `x` is at byte offset 6 (`const ` is 6 bytes including the space).
    let x_off = src.find('x').unwrap() as i32;
    assert_eq!(
        diags[0].start, x_off,
        "TS2322 span must start at the name `x` (skipping leading trivia), not the space"
    );
}

