// TEMP(Round 31): sole-flip dump. Walks the full corpus and, for each FAILED
// case, computes the DISTINCT `(kind,code)` clusters in its mismatch multiset.
// A case is a SOLE-cluster flip for `(kind,code)` when its ENTIRE mismatch set
// is that ONE cluster (possibly with multiple occurrences) — i.e. it flips to
// byte-exact PASS if ONLY that cluster is fixed alone. REMOVE before finishing.
#[test]
#[ignore = "temp Round 31 sole-flip dump; run with `-- --ignored --nocapture`"]
fn temp_round31_sole_flip_dump() {
    use crate::CaseDiff;
    let testdata = Path::new(tsgo_repo::test_data_path());
    let runner = CompilerBaselineRunner::new(CompilerTestType::Regression, testdata);
    let cases = runner.full_corpus(FULL_CORPUS_DENYLIST);

    let summary = with_silenced_panics(|| {
        std::thread::Builder::new()
            .stack_size(1024 * 1024 * 1024)
            .spawn(move || {
                let _capture = PanicLocationCapture::install();
                runner.run_cases(cases)
            })
            .expect("spawn dump thread")
            .join()
            .expect("dump thread panicked")
    });

    let counts = summary.counts();
    println!(
        "=== Round 31 sole-flip dump: passed {} failed {} errored {} ===",
        counts.passed, counts.failed, counts.errored
    );
    let hist = summary.histogram();
    println!(
        "category: no_baseline_but_errors ×{}, missing_all_errors ×{}, divergent ×{}",
        hist.no_baseline_but_errors, hist.missing_all_errors, hist.divergent
    );
    println!("top extra: {:?}", hist.top_extra(25));
    println!("top missing: {:?}", hist.top_missing(25));

    let kind_label = |k: MismatchKind| -> &'static str {
        match k {
            MismatchKind::Missing => "missing",
            MismatchKind::Extra => "extra",
            MismatchKind::WrongCode => "wrong_code",
            MismatchKind::WrongSpan => "wrong_span",
            MismatchKind::WrongMessage => "wrong_message",
        }
    };
    // cluster "(label,code)" -> sorted list of (case, occurrence count)
    let mut sole: indexmap::IndexMap<(&'static str, u32), Vec<(String, usize)>> =
        indexmap::IndexMap::new();
    let describe = |diff: &CaseDiff| -> indexmap::IndexMap<(&'static str, u32), usize> {
        let mut m: indexmap::IndexMap<(&'static str, u32), usize> = indexmap::IndexMap::new();
        for mm in &diff.mismatches {
            *m.entry((kind_label(mm.kind), mm.code)).or_insert(0) += 1;
        }
        m
    };
    for r in summary.results() {
        let Some(diff) = r.diff.as_ref() else { continue };
        let clusters = describe(diff);
        if clusters.len() == 1 {
            let (&key, &occ) = clusters.iter().next().unwrap();
            sole.entry(key).or_default().push((r.name.clone(), occ));
        }
    }
    let mut entries: Vec<((&'static str, u32), Vec<(String, usize)>)> = sole.into_iter().collect();
    entries.sort_by(|a, b| b.1.len().cmp(&a.1.len()).then_with(|| a.0.cmp(&b.0)));
    println!("--- SOLE-FLIP clusters (entire mismatch set is one cluster) ---");
    for ((label, code), cases) in &entries {
        println!("  {label} TS{code} : sole-flip {}", cases.len());
        for (name, occ) in cases {
            println!("      {name} (×{occ})");
        }
    }
}

